const query = ($('Auth Guard').first()?.json?.body?.query || $('Auth Guard').first()?.json?.body?.q || '').toLowerCase();

// Local results
const local = ($('Search Postgres').all()||[]).map(i=>i.json).filter(i=>i&&!i.error).map(r=>({title:r.title||r.opp_title||'Untitled',agency:r.agency||'',department:r.department||r.dept||'',naics:r.naics_code||'',set_aside:r.set_aside||'',estimated_value:r.estimated_value||0,deadline:r.response_deadline||null,source_url:r.source_url||'',source:'Local',solicitation_number:r.solicitation_number||'',place_of_performance:r.place_of_performance||''}));

// SAM.gov results
let sam = [];
try {
  const samData = $('SAM.gov Search').first()?.json;
  const opps = samData?.opportunitiesData || samData?.data || [];
  sam = opps.slice(0,10).map(o=>({title:o.title||'Untitled',agency:o.department||o.fullParentPathName||'',department:o.department||'',naics:o.naicsCode||'',set_aside:o.typeOfSetAside||'',estimated_value:0,deadline:o.responseDeadLine||o.archiveDate||null,source_url:'https://sam.gov/opp/'+o.noticeId,source:'SAM.gov',solicitation_number:o.solicitationNumber||'',place_of_performance:o.placeOfPerformance?.city?.name||''}));
} catch(e){}

// Tavily results
let web = [];
try {
  const tavData = $('Tavily Web Search').first()?.json;
  const results = tavData?.results || [];
  web = results.map(r=>({title:r.title||'Untitled',agency:'',department:'',naics:'',set_aside:'',estimated_value:0,deadline:null,source_url:r.url||'',source:'Web',solicitation_number:'',place_of_performance:''}));
} catch(e){}

// Merge and deduplicate
const all = [...local, ...sam, ...web];
const seen = new Set();
const deduped = all.filter(r => {
  const key = r.solicitation_number || r.title;
  if (!key || seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Sort: deadline soonest first, then by source priority
deduped.sort((a,b) => {
  if (a.deadline && b.deadline) return new Date(a.deadline) - new Date(b.deadline);
  if (a.deadline) return -1;
  if (b.deadline) return 1;
  const pri = {Local:0,'SAM.gov':1,Web:2};
  return (pri[a.source]||3) - (pri[b.source]||3);
});

const sources = [...new Set(deduped.map(r=>r.source))];
return [{json:{results:deduped.slice(0,30),total:deduped.length,sources,search_query:query,searched_at:new Date().toISOString()}}];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];
